  ws.addEventListener('message', (ev) => {
    console.log(String(ev.data));
  });
  ws.addEventListener('close', () => process.exit(0));
  ws.addEventListener('error', () => {
    console.error('WebSocket error');
    process.exit(1);
  });
  return;
}

